// Regenerate .htaccess for Hostinger Phusion Passenger
// Run from Hostinger hPanel → Node.js → Run Script after git deployment:
//   node scripts/fix-htaccess.cjs
const fs = require("fs");
const path = require("path");

const targetDir = path.resolve(__dirname, "..");
const htaccessPath = path.join(targetDir, ".htaccess");
const appRoot = targetDir.replace(/\\/g, "/");
const nodeBin = (process.execPath || "/usr/bin/node").replace(/\\/g, "/");
const startupFile = "server.js";

const content = [
  "# Phusion Passenger configuration for Node.js",
  "# Auto-generated by fix-htaccess.cjs",
  "",
  "PassengerAppRoot " + appRoot,
  "PassengerBaseURI /",
  "PassengerNodejs " + nodeBin,
  "PassengerAppType node",
  "PassengerStartupFile " + startupFile,
  "",
].join("\n");

fs.writeFileSync(htaccessPath, content, "utf8");
console.log("OK .htaccess regenerated at " + htaccessPath);
console.log("  AppRoot: " + appRoot);
console.log("  Node:    " + nodeBin);
